INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 103811, 309, 309019, 0, 0, "あのお料理美味しそう……\nお姉ちゃんにも教えてあげなくちゃ。", 11, 0, 0.5, 0);
