INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 100911, 311, 311006, 0, 0, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES ("", 311006, 311, 311007, "", "", "", 91, "", "", "");
