INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 101311, 311, 311010, 0, 0, "アンナたそアンナたそ！\nおせち料理、美味しそうですぞ！\nさあ、おあがりよ！！", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES ("", 311010, 311, 311011, "", "", "", 91, "", "", "");
