INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 105111, 311, 311014, 0, 0, "医食同源……って知ってるかしら？\n長寿を願う料理には、なにかしらの\n効能があるものも多いのよ。", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES ("", 311014, 311, 311015, "", "", "", 91, "", "", "");
