INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 101831, 312, 312001, 0, 0, "素敵な新年会ね～\n他の学校の人たちも来ているようだし\nお話を伺いに行こうかしら？", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (1, 101831, 312, 312002, "", 0.2, "nop_talk_joy1", 3, "", "", "");
