INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 101611, 312, 312005, 0, 0, "見て見てミサキっち！\nあそこの料理すっごく美味しそう！", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (1, 101611, 312, 312006, "", 0.2, "nop_talk_surprise_kira", 3, "", "", "");
