INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 105011, 312, 312009, 0, 0, "えー？　でもあれって野菜じゃない？\n別に、大人のレディだから\n食べられないわけじゃないけど？", 11, 0, 0.5, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (1, 105011, 312, 312010, "", 0.2, "nop_talk_sad", 3, "", "", "");
