INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (8, 103731, 506, 506013, 0, 0, "クリスティーナ！\nあなたはいったいどの面下げて\n私たちの前に……", 11, 0, 0.5, 1);
